// Parse QUITTANCE_2026.csv (séparateur ; , quotes, BOM, CRLF)
//  [5] compagnie  [11] prime  [12] commission  [13] commission_sa  [14] date JJ/MM/AAAA
const item = $input.first();
if (!item.binary) throw new Error('Aucune donnée binaire reçue du noeud Download CSV');
const propName = item.binary.data ? 'data' : Object.keys(item.binary)[0];
const binMeta = item.binary[propName];
let buffer;
if (binMeta && binMeta.data) buffer = Buffer.from(binMeta.data, 'base64');
else buffer = await this.helpers.getBinaryDataBuffer(0, propName);
let txt = buffer.toString('utf8').replace(/^\uFEFF/, '');
const lines = txt.split(/\r?\n/);

const num = (s) => {
  s = (s || '').toString().trim();
  if (!s) return null;
  s = s.replace(/\s/g, '');
  if (s.includes(',') && s.includes('.')) s = s.replace(/\./g, '').replace(',', '.');
  else s = s.replace(',', '.');
  const n = parseFloat(s);
  return isNaN(n) ? null : n;
};
const toISO = (s) => {
  s = (s || '').toString().trim();
  const p = s.split('/');
  if (p.length === 3 && p[2].length === 4) return `${p[2]}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}`;
  return null;
};
const clean = (s) => (s || '').toString().trim().replace(/^"|"$/g, '');

const rows = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i];
  if (!line || !line.trim()) continue;
  const f = line.split(';');
  if (f.length < 15) continue;
  const compagnie = clean(f[5]);
  const prime = num(clean(f[11]));
  const commission = num(clean(f[12]));
  const commission_sa = num(clean(f[13]));
  const date_comptable = toISO(clean(f[14]));
  if (!compagnie && prime === null && commission === null) continue;
  rows.push({ compagnie, prime_totale: prime, commission, commission_sa, date_comptable });
}

// 1 item par lot de 1000 ; le noeud HTTP suivant itère nativement sur chaque item
const CHUNK = 1000;
const out = [];
for (let i = 0; i < rows.length; i += CHUNK) {
  out.push({ json: { rows: rows.slice(i, i + CHUNK), total: rows.length, lot: (i / CHUNK) + 1 } });
}
if (out.length === 0) out.push({ json: { rows: [], total: 0, lot: 0 } });
return out;

const total = $('🔧 Parse CSV + lots de 1000').first().json.total;
console.log(`=== IMPORT QUITTANCES 2026 : ${total} lignes envoyées ===`);
return [{ json: { ok: true, total } }];
